import React from 'react';
import styled from 'styled-components/macro';
import Product from '../../../../components/Product';
import Top from './Top';
import shirt from '../../../../assets/green-t-shirt.jpg';

const Grid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, auto));
  grid-gap: 30px;
  align-content: start;

  .message {
    grid-column: 1/-1;
    justify-self: center;
  }
`;

export default ({ products }) => (
  <Grid>
    <Top />
    <Product img={shirt} name="Green T-Shirt" price={19.99} />
    <Product img={shirt} name="Green T-Shirt" price={19.99} />
    <Product img={shirt} name="Green T-Shirt" price={19.99} />
    <Product img={shirt} name="Green T-Shirt" price={19.99} />
    <Product img={shirt} name="Green T-Shirt" price={19.99} />
    <Product img={shirt} name="Green T-Shirt" price={19.99} />
    <Product img={shirt} name="Green T-Shirt" price={19.99} />
    <Product img={shirt} name="Green T-Shirt" price={19.99} />
    <Product img={shirt} name="Green T-Shirt" price={19.99} />
    <Product img={shirt} name="Green T-Shirt" price={19.99} />
    <Product img={shirt} name="Green T-Shirt" price={19.99} />
    <Product img={shirt} name="Green T-Shirt" price={19.99} />
    {/* {products.length === 0 && <h1 className="message">No results found.</h1>}
    {products.map(product => (
      <Product img={product.img} name={product.name} price={product.price} />
    ))} */}
  </Grid>
);
